import { useState, useEffect, useMemo, useRef, useCallback } from "react";

// ─── WHATSAPP ─────────────────────────────────────────────────────────────────
const WA_NUMBER = "541130840455";
const waLink = (v) => {
  const msg = encodeURIComponent(
    `¡Hola Ramos Mejia Motors! 👋 Me interesa consultar sobre el *${v.name}* (${v.year}, ${v.km.toLocaleString("es-AR")} km, $${Number(v.price).toLocaleString("es-AR")}). ¿Está disponible?`
  );
  return `https://wa.me/${WA_NUMBER}?text=${msg}`;
};

