// Color palettes per vehicle
const PALETTES = {
  auto:      [["#1a3a8a","#0d2060"],["#8a1a2a","#601010"],["#1a6a3a","#0d4020"],["#5a1a8a","#3a0d60"],["#8a6a1a","#604010"]],
  camioneta: [["#1a5a3a","#0d3a20"],["#1a2a6a","#0d1a4a"],["#6a1a1a","#4a0d0d"],["#4a3a1a","#302510"],["#2a2a2a","#1a1a1a"]],
  moto:      [["#aa1122","#770d16"],["#1a1aaa","#0d0d77"],["#aa5500","#773a00"],["#1a1a1a","#0d0d0d"],["#006622","#004416"]],
  otros:     [["#3a5a20","#253c14"],["#5a3a1a","#3c280d"],["#1a3a5a","#0d283c"],["#4a1a3a","#300d27"],["#5a5a1a","#3c3c0d"]],
};

const SHAPES = { auto: "sedan", camioneta: "suv", moto: "moto", otros: "jeep" };

function getVehicleImage(vehicle, index = 0) {
  const palette = PALETTES[vehicle.type] || PALETTES.auto;
  const [c1, c2] = palette[vehicle.id % palette.length];
  const shape = SHAPES[vehicle.type] || "sedan";
  // Each photo index shifts the palette slightly
  const shift = index % palette.length;
  const [sc1, sc2] = palette[(vehicle.id + shift) % palette.length];
  return CAR_SVGS[shape](index === 0 ? c1 : sc1, index === 0 ? c2 : sc2);
}

