// ─── PUBLIC SITE ──────────────────────────────────────────────────────────────
function PublicSite({ vehicles, onGoAdmin, deepVehicleId, onClearDeep }) {
  const [typeFilter, setTypeFilter] = useState("");
  const [showAdv, setShowAdv] = useState(false);
  const [adv, setAdv] = useState({ minKm:"", maxKm:"", minPrice:"", maxPrice:"", minYear:"", maxYear:"" });
  const [detail, setDetail] = useState(null);
  const [activeSection, setActiveSection] = useState("");

  // Auto-open vehicle detail when arriving via QR deep link
  useEffect(() => {
    if (deepVehicleId) {
      const v = vehicles.find(x => x.id === deepVehicleId);
      if (v) setDetail(v);
    }
  }, [deepVehicleId, vehicles]);

  useEffect(() => {
    const sections = ["ofertas", "vehiculos"];
    const observers = sections.map(id => {
      const el = document.getElementById(id);
      if (!el) return null;
      const obs = new IntersectionObserver(
        ([entry]) => { if (entry.isIntersecting) setActiveSection(id); },
        { rootMargin: "-40% 0px -55% 0px", threshold: 0 }
      );
      obs.observe(el);
      return obs;
    });
    return () => observers.forEach(o => o && o.disconnect());
  }, []);

  const setA = (k, val) => setAdv(a => ({ ...a, [k]:val }));
  const resetAll = () => { setTypeFilter(""); setAdv({ minKm:"", maxKm:"", minPrice:"", maxPrice:"", minYear:"", maxYear:"" }); };
  const advCount = Object.values(adv).filter(Boolean).length;

  const filtered = useMemo(() => vehicles.filter(v => {
    if (typeFilter && v.type !== typeFilter) return false;
    if (adv.minKm && v.km < +adv.minKm) return false;
    if (adv.maxKm && v.km > +adv.maxKm) return false;
    if (adv.minPrice && v.price < +adv.minPrice) return false;
    if (adv.maxPrice && v.price > +adv.maxPrice) return false;
    if (adv.minYear && v.year < +adv.minYear) return false;
    if (adv.maxYear && v.year > +adv.maxYear) return false;
    return true;
  }), [vehicles, typeFilter, adv]);

  const offers = vehicles.filter(v => v.offer);

  return (
    <>
      <nav className="navbar">
        <div className="logo" onClick={() => window.scrollTo({ top:0, behavior:"smooth" })}>
          <LogoImg height={40} />
        </div>
        <div className="nav-links">
          {offers.length > 0 && <button className={`nav-link${activeSection === "ofertas" ? " nav-link-active" : ""}`} onClick={() => document.getElementById("ofertas")?.scrollIntoView({ behavior:"smooth" })}>Ofertas</button>}
          <button className={`nav-link${activeSection === "vehiculos" ? " nav-link-active" : ""}`} onClick={() => document.getElementById("vehiculos")?.scrollIntoView({ behavior:"smooth" })}>Vehículos</button>
        </div>
        <button className="nav-cta" onClick={onGoAdmin}>Admin ↗</button>
      </nav>

      <div className="hero">
        <div className="hero-badge">🏎️ {vehicles.length}+ vehículos disponibles</div>
        <h1 className="hero-title">Tu próximo auto<br /><span className="hl">en Ramos Mejía.</span></h1>
        <p className="hero-sub">La agencia de confianza de la zona oeste. Autos, camionetas y motos con garantía y financiación.</p>
        <div className="hero-stats">
          <div className="stat"><div className="stat-num">{vehicles.length}+</div><div className="stat-label">Vehículos</div></div>
          <div className="stat"><div className="stat-num">{offers.length}</div><div className="stat-label">Ofertas</div></div>
          <div className="stat"><div className="stat-num">100%</div><div className="stat-label">Confianza</div></div>
        </div>
      </div>

      {offers.length > 0 && (
        <div id="ofertas" className="section">
          <div className="section-hd">
            <div>
              <h2 className="section-title">Ofertas <span>imperdibles</span></h2>
              <p className="section-sub">Avanza automáticamente · Hacé click para ver detalles</p>
            </div>
          </div>
          <OffersCarousel offers={offers} onCardClick={setDetail} />
        </div>
      )}

      <div id="vehiculos" className="section">
        <div className="section-hd">
          <div>
            <h2 className="section-title">Todos los <span>vehículos</span></h2>
            <p className="section-sub">Hacé click en una tarjeta para ver detalles y consultar</p>
          </div>
        </div>

        <div className="filter-bar">
          <div className="type-pills">
            {[{val:"",label:"🚘 Todos"},{val:"auto",label:"🚗 Autos"},{val:"camioneta",label:"🛻 Camionetas"},{val:"moto",label:"🏍️ Motos"},{val:"otros",label:"🚙 Otros"}].map(t => (
              <button key={t.val} className={`type-pill${typeFilter === t.val ? " active" : ""}`} onClick={() => setTypeFilter(t.val)}>{t.label}</button>
            ))}
          </div>
          <div className="filter-row2">
            <button className={`adv-toggle${advCount > 0 ? " on" : ""}`} onClick={() => setShowAdv(s => !s)}>
              {showAdv ? "▲" : "▼"} Filtros avanzados
              {advCount > 0 && <span className="badge-count">{advCount}</span>}
            </button>
            {(typeFilter || advCount > 0) && <button className="reset-lnk" onClick={resetAll}>✕ Limpiar todo</button>}
            <span className="res-count">{filtered.length} resultado{filtered.length !== 1 ? "s" : ""}</span>
          </div>
          {showAdv && (
            <div className="adv-panel">
              {[{k:"minKm",l:"Km mín."},{k:"maxKm",l:"Km máx."},{k:"minPrice",l:"Precio mín. $"},{k:"maxPrice",l:"Precio máx. $"},{k:"minYear",l:"Año mín."},{k:"maxYear",l:"Año máx."}].map(f => (
                <div className="adv-field" key={f.k}>
                  <label>{f.l}</label>
                  <ClearableInput value={adv[f.k]} onChange={val => setA(f.k, val)} />
                </div>
              ))}
            </div>
          )}
        </div>

        {filtered.length === 0 ? (
          <div className="no-results"><span className="no-results-icon">🔍</span><h3>Sin resultados</h3><p style={{marginTop:8}}>Probá con otros filtros</p></div>
        ) : (
          <div className="vehicles-grid">
            {filtered.map(v => (
              <div className="vehicle-card" key={v.id} onClick={() => setDetail(v)}>
                <div className="card-img-wrap">
                  <img className="card-img" src={v.photos[0]} alt={v.name} />
                  <div className="card-gradient" />
                  {v.offer && <div className="card-offer-badge">{v.offerTag}</div>}
                </div>
                <div className="card-body">
                  <span className={`vehicle-type-badge ${BADGE[v.type]}`}>{TYPE_LABELS[v.type]}</span>
                  <div className="vehicle-name">{v.name}</div>
                  <div className="vehicle-meta">
                    <span className="vm">📅 {v.year}</span>
                    <span className="vm">🛣️ {v.km.toLocaleString("es-AR")} km</span>
                    <span className="vm">⛽ {v.fuel}</span>
                  </div>
                  <div className="vehicle-price-lbl">Precio</div>
                  <div className="vehicle-price">{fmt(v.price, v.currency)}</div>
                  <div className="currency-badge" data-cur={v.currency||"ARS"}>{v.currency||"ARS"}</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <footer className="footer">
        <div className="footer-logo-wrap"><LogoImg height={48} /></div>
        <p>© 2025 Ramos Mejía Motors · Ramos Mejía, Buenos Aires, Argentina</p>
      </footer>
      {detail && <VehicleDetail v={detail} onClose={() => setDetail(null)} />}
    </>
  );
}

