// ─── VEHICLE FORM MODAL ───────────────────────────────────────────────────────
function VehicleModal({ vehicle, onSave, onClose }) {
  const empty = { name:"", type:"auto", year:2024, km:0, price:0, currency:"ARS", fuel:"Nafta", color:"", desc:"", offer:false, offerTag:"", photos:[], specs:{} };
  const [form, setForm] = useState(vehicle || empty);
  // photos state: array of data URIs (real) or SVG data URIs (generated)
  const [photos, setPhotos] = useState(vehicle?.photos || []);
  const [dragOver, setDragOver] = useState(false);
  const [dragIndex, setDragIndex] = useState(null);
  const fileInputRef = useRef(null);

  const set = (k, val) => setForm(f => ({...f,[k]:val}));

  const readFiles = (files) => {
    Array.from(files).forEach(file => {
      if (!file.type.startsWith("image/")) return;
      const reader = new FileReader();
      reader.onload = e => setPhotos(p => [...p, e.target.result]);
      reader.readAsDataURL(file);
    });
  };

  const handleDrop = (e) => {
    e.preventDefault(); setDragOver(false);
    readFiles(e.dataTransfer.files);
  };

  const removePhoto = (idx) => setPhotos(p => p.filter((_,i) => i !== idx));

  const movePhoto = (from, to) => {
    setPhotos(p => {
      const arr = [...p];
      const [item] = arr.splice(from, 1);
      arr.splice(to, 0, item);
      return arr;
    });
  };

  const handleThumbDragStart = (index) => {
    setDragIndex(index);
  };

  const handleThumbDragOver = (e, index) => {
    e.preventDefault();
    if (dragIndex === null || dragIndex === index) return;
    movePhoto(dragIndex, index);
    setDragIndex(index);
  };

  const handleThumbDragEnd = () => {
    setDragIndex(null);
  };

  const handleSave = () => {
    if (!form.name.trim()) return;
    const draft = { ...form, id: vehicle?.id || Date.now() };
    // Use real photos if any uploaded, otherwise fallback to generated SVGs
    draft.photos = photos.length > 0 ? photos : [0,1,2].map(i => getVehicleImage(draft, i));
    onSave(draft);
  };

  return (
    <div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal">
        <button className="close-modal" onClick={onClose}>×</button>
        <div className="modal-title">{vehicle?"Editar vehículo":"Nuevo vehículo"}</div>
        <div className="modal-sub">{vehicle?`Editando: ${vehicle.name}`:"Completá los datos"}</div>
        <div className="form-row">
          <div className="form-field"><label>Nombre *</label><input className="form-input" value={form.name} onChange={e=>set("name",e.target.value)} placeholder="Ej: Toyota Corolla"/></div>
          <div className="form-field"><label>Tipo</label><select className="form-select" value={form.type} onChange={e=>set("type",e.target.value)}><option value="auto">Auto</option><option value="camioneta">Camioneta</option><option value="moto">Moto</option><option value="otros">Otros</option></select></div>
        </div>
        <div className="form-row">
          <div className="form-field"><label>Año</label><input className="form-input" type="number" value={form.year} onChange={e=>set("year",+e.target.value)}/></div>
          <div className="form-field"><label>Kilometraje</label><input className="form-input" type="number" value={form.km} onChange={e=>set("km",+e.target.value)}/></div>
        </div>
        <div className="form-row">
          <div className="form-field">
            <label>Precio</label>
            <div style={{display:"flex",gap:6}}>
              <select className="form-select" style={{width:90,flexShrink:0}} value={form.currency||"ARS"} onChange={e=>set("currency",e.target.value)}>
                <option value="ARS">$ ARS</option>
                <option value="USD">USD</option>
              </select>
              <input className="form-input" type="number" value={form.price} onChange={e=>set("price",+e.target.value)} style={{flex:1}}/>
            </div>
          </div>
          <div className="form-field"><label>Combustible</label><select className="form-select" value={form.fuel} onChange={e=>set("fuel",e.target.value)}><option>Nafta</option><option>Diesel</option><option>GNC</option><option>Eléctrico</option><option>Híbrido</option></select></div>
        </div>
        <div className="form-field"><label>Color</label><input className="form-input" value={form.color} onChange={e=>set("color",e.target.value)} placeholder="Ej: Rojo"/></div>
        <div className="form-field"><label>Descripción</label><textarea className="form-textarea" value={form.desc} onChange={e=>set("desc",e.target.value)} placeholder="Descripción del vehículo..."/></div>
        <label className="form-check"><input type="checkbox" checked={form.offer} onChange={e=>set("offer",e.target.checked)}/><span>🔥 Marcar como oferta destacada</span></label>
        {form.offer && <div className="form-field"><label>Etiqueta</label><input className="form-input" value={form.offerTag} onChange={e=>set("offerTag",e.target.value)} placeholder="Ej: -15% OFF"/></div>}

        {/* ── FOTOS ── */}
        <div className="photo-section">
          <div className="photo-section-hd">
            <span className="photo-section-title">📷 Fotos</span>
            <span className="photo-section-hint">{photos.length} foto{photos.length!==1?"s":""} · La primera es la principal</span>
          </div>

          {/* Drop zone */}
          <div
            className={`photo-dropzone${dragOver?" dz-over":""}`}
            onDragOver={e=>{e.preventDefault();setDragOver(true);}}
            onDragLeave={()=>setDragOver(false)}
            onDrop={handleDrop}
            onClick={()=>fileInputRef.current?.click()}
          >
            <div className="dz-icon">📁</div>
            <div className="dz-text">Arrastrá fotos aquí o <span className="dz-link">seleccioná archivos</span></div>
            <div className="dz-sub">JPG, PNG, WEBP</div>
            <input ref={fileInputRef} type="file" accept="image/*" multiple style={{display:"none"}} onChange={e=>readFiles(e.target.files)}/>
          </div>

          {/* Thumbnails grid */}
          {photos.length > 0 && (
            <div className="photo-thumbs">
              {photos.map((src, i) => (
                <div
                  key={i}
                  className="photo-thumb-wrap"
                  draggable
                  onDragStart={() => handleThumbDragStart(i)}
                  onDragOver={(e) => handleThumbDragOver(e, i)}
                  onDragEnd={handleThumbDragEnd}
                >
                  {i === 0 && <div className="photo-thumb-badge">Principal</div>}
                  <img src={src} alt="" className="photo-thumb-img"/>
                  <div className="photo-thumb-actions">
                    {i > 0 && <button className="pth-btn" title="Mover izquierda" onClick={()=>movePhoto(i,i-1)}>‹</button>}
                    {i < photos.length-1 && <button className="pth-btn" title="Mover derecha" onClick={()=>movePhoto(i,i+1)}>›</button>}
                    <button className="pth-btn pth-del" title="Eliminar" onClick={()=>removePhoto(i)}>✕</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="modal-actions">
          <button className="cancel-btn" onClick={onClose}>Cancelar</button>
          <button className="save-btn" onClick={handleSave}>Guardar vehículo</button>
        </div>
      </div>
    </div>
  );
}

// ─── QR GENERATOR (pure JS, no libs) ─────────────────────────────────────────
// Minimal QR encoder for URLs — uses qrcode-generator logic inline
// ─── QR MODAL ─────────────────────────────────────────────────────────────────
// ⚙️  Cambiá esta URL por la del sitio cuando lo despliegues en producción
const SITE_BASE_URL = window.location.origin + window.location.pathname.replace(/\/$/, "");

function QRModal({ vehicle, onClose }) {
  const canvasRef = useRef(null);
  const url = `${SITE_BASE_URL}/#/v/${vehicle.id}`;

  useEffect(() => {
    const esc = e => e.key === "Escape" && onClose();
    window.addEventListener("keydown", esc);
    return () => window.removeEventListener("keydown", esc);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Load qrcode-svg or use pure-canvas QR encoder
    // We use a lightweight QR matrix encoder written inline to avoid DOM-manipulating libs
    const drawQR = (matrix, canvas, size) => {
      const ctx = canvas.getContext("2d");
      const n = matrix.length;
      const cell = Math.floor(size / n);
      const pad = Math.floor((size - cell * n) / 2);
      canvas.width = size; canvas.height = size;
      ctx.fillStyle = "#ffffff"; ctx.fillRect(0, 0, size, size);
      ctx.fillStyle = "#000000";
      for (let r = 0; r < n; r++)
        for (let c = 0; c < n; c++)
          if (matrix[r][c]) ctx.fillRect(pad + c * cell, pad + r * cell, cell, cell);
    };

    // Dynamically load qrcode-generator (data-only, no DOM writing)
    const loadAndRender = () => {
      if (window.qrcode) { render(); return; }
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/qrcode-generator/1.4.4/qrcode.min.js";
      s.onload = render;
      s.onerror = () => console.error("QR lib failed to load");
      document.head.appendChild(s);
    };

    const render = () => {
      try {
        const qr = window.qrcode(0, "H");
        qr.addData(url);
        qr.make();
        const n = qr.getModuleCount();
        const matrix = Array.from({length: n}, (_, r) =>
          Array.from({length: n}, (_, c) => qr.isDark(r, c))
        );
        drawQR(matrix, canvas, 220);
      } catch(e) { console.error("QR render error", e); }
    };

    loadAndRender();
  }, [url]);

  const downloadQR = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const a = document.createElement("a");
    a.href = canvas.toDataURL("image/png");
    a.download = `QR-${vehicle.name.replace(/\s+/g, "-")}.png`;
    a.click();
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal modal-sm" style={{textAlign:"center"}}>
        <button className="close-modal" onClick={onClose}>×</button>
        <div style={{fontSize:"1.5rem",marginBottom:4}}>📲</div>
        <div className="modal-title">Código QR</div>
        <div className="modal-sub" style={{marginBottom:16}}>{vehicle.name} · {vehicle.year}</div>

        <div style={{display:"inline-flex",padding:14,background:"#fff",borderRadius:14,marginBottom:14,boxShadow:"0 4px 24px rgba(0,0,0,0.3)"}}>
          <canvas ref={canvasRef} width={220} height={220} style={{display:"block",borderRadius:4}}/>
        </div>

        <div style={{fontSize:"0.72rem",color:"var(--muted)",wordBreak:"break-all",margin:"0 0 16px",padding:"6px 10px",background:"rgba(255,255,255,0.04)",borderRadius:8,border:"1px solid rgba(255,255,255,0.07)"}}>
          {url}
        </div>

        <div style={{fontSize:"0.8rem",color:"var(--muted)",marginBottom:18,lineHeight:1.5}}>
          Escaneá este QR para ver los detalles del vehículo.<br/>
          Podés imprimirlo y pegarlo en el auto.
        </div>

        <div style={{display:"flex",gap:10}}>
          <button className="cancel-btn" style={{flex:1}} onClick={onClose}>Cerrar</button>
          <button className="save-btn" style={{flex:1}} onClick={downloadQR}>⬇ Descargar PNG</button>
        </div>
      </div>
    </div>
  );
}

// ─── ADMIN PANEL ──────────────────────────────────────────────────────────────
function AdminPanel({ vehicles, setVehicles, onLogout }) {
  const [modal, setModal] = useState(null);
  const [confirmDel, setConfirmDel] = useState(null);
  const [qrVehicle, setQrVehicle] = useState(null);
  const [toast, setToast] = useState(null);
  const [sortConfig, setSortConfig] = useState({ key: null, direction: null });
  const API_BASE = "http://localhost:4000/api";
  const showToast = (msg, type="success") => { setToast({msg,type}); setTimeout(()=>setToast(null),3000); };
  const handleSave = async (v) => {
    try {
      if (modal === "add") {
        const res = await fetch(`${API_BASE}/vehicles`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(v),
        });
        if (!res.ok) throw new Error("HTTP " + res.status);
        const saved = await res.json();
        setVehicles(p => [...p, saved]);
        showToast("✅ Vehículo agregado");
      } else {
        const res = await fetch(`${API_BASE}/vehicles/${v.id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(v),
        });
        if (!res.ok) throw new Error("HTTP " + res.status);
        const saved = await res.json();
        setVehicles(p => p.map(x => x.id === saved.id ? saved : x));
        showToast("✅ Vehículo actualizado");
      }
    } catch (e) {
      console.error("Error guardando vehículo", e);
      showToast("⚠️ Error guardando vehículo", "error");
    } finally {
      setModal(null);
    }
  };
  const handleDeleteConfirmed = async () => {
    try {
      const id = confirmDel.id;
      const res = await fetch(`${API_BASE}/vehicles/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("HTTP " + res.status);
      setVehicles(p => p.filter(v => v.id !== id));
      showToast(`🗑 "${confirmDel.name}" eliminado`, "error");
    } catch (e) {
      console.error("Error eliminando vehículo", e);
      showToast("⚠️ Error eliminando vehículo", "error");
    } finally {
      setConfirmDel(null);
    }
  };
  const c = { total:vehicles.length, offers:vehicles.filter(v=>v.offer).length, autos:vehicles.filter(v=>v.type==="auto").length, motos:vehicles.filter(v=>v.type==="moto").length };

  const handleSort = (key) => {
    setSortConfig((prev) => {
      if (prev.key !== key) {
        return { key, direction: "asc" };
      }
      if (prev.direction === "asc") {
        return { key, direction: "desc" };
      }
      return { key: null, direction: null };
    });
  };

  const sortedVehicles = useMemo(() => {
    if (!sortConfig.key || !sortConfig.direction) return vehicles;
    const sorted = [...vehicles];
    const { key, direction } = sortConfig;
    const dir = direction === "asc" ? 1 : -1;

    const getValue = (v) => {
      switch (key) {
        case "name": return v.name ?? "";
        case "type": return v.type ?? "";
        case "year": return v.year ?? 0;
        case "km": return v.km ?? 0;
        case "price": return Number(v.price) || 0;
        case "currency": return v.currency ?? "";
        case "offer": return v.offer ? (v.offerTag ?? "Sí") : "";
        default: return "";
      }
    };

    sorted.sort((a, b) => {
      const va = getValue(a);
      const vb = getValue(b);
      if (typeof va === "number" && typeof vb === "number") {
        return (va - vb) * dir;
      }
      return String(va).localeCompare(String(vb), "es-AR") * dir;
    });

    return sorted;
  }, [vehicles, sortConfig]);

  const sortIcon = (key) => {
    if (sortConfig.key !== key || !sortConfig.direction) return null;
    return sortConfig.direction === "asc" ? " ▲" : " ▼";
  };

  return (
    <div className="admin-layout">
      <aside className="admin-sidebar">
        <div className="sidebar-logo-wrap"><LogoImg height={38} /></div>
        <div className="sidebar-role">Panel de Administración</div>
        <div className="sidebar-label">Menú</div>
        <button className="sidebar-item active">📦 Vehículos</button>
        <button className="sidebar-item">📊 Estadísticas</button>
        <button className="sidebar-item">🔔 Consultas</button>
        <button className="sidebar-item">⚙️ Config</button>
        <button className="sidebar-logout" onClick={onLogout}>⏻ Salir</button>
      </aside>
      <main className="admin-main">
        <div className="admin-page-title">Gestión de Vehículos</div>
        <div className="admin-page-sub">CRUD completo del inventario</div>
        <div className="stats-row">
          <div className="stat-card"><div className="stat-card-label">Total</div><div className="stat-card-num accent">{c.total}</div></div>
          <div className="stat-card"><div className="stat-card-label">En oferta</div><div className="stat-card-num gold">{c.offers}</div></div>
          <div className="stat-card"><div className="stat-card-label">Autos</div><div className="stat-card-num purple">{c.autos}</div></div>
          <div className="stat-card"><div className="stat-card-label">Motos</div><div className="stat-card-num red">{c.motos}</div></div>
        </div>
        <div className="admin-table-wrap">
          <div className="admin-table-header">
            <div className="admin-table-title">Inventario completo</div>
            <button className="add-btn" onClick={()=>setModal("add")}>+ Agregar</button>
          </div>
          <div style={{overflowX:"auto"}}>
            <table>
              <thead>
                <tr>
                  <th onClick={()=>handleSort("name")} style={{cursor:"pointer"}}>Vehículo{sortIcon("name")}</th>
                  <th onClick={()=>handleSort("type")} style={{cursor:"pointer"}}>Tipo{sortIcon("type")}</th>
                  <th onClick={()=>handleSort("year")} style={{cursor:"pointer"}}>Año{sortIcon("year")}</th>
                  <th onClick={()=>handleSort("km")} style={{cursor:"pointer"}}>Km{sortIcon("km")}</th>
                  <th onClick={()=>handleSort("price")} style={{cursor:"pointer"}}>Precio{sortIcon("price")}</th>
                  <th onClick={()=>handleSort("currency")} style={{cursor:"pointer"}}>Moneda{sortIcon("currency")}</th>
                  <th onClick={()=>handleSort("offer")} style={{cursor:"pointer"}}>Oferta{sortIcon("offer")}</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {sortedVehicles.map(v => (
                  <tr key={v.id}>
                    <td className="td-name">
                      <img src={v.photos?.[0]} alt="" style={{width:44,height:32,objectFit:"cover",borderRadius:7,marginRight:8,verticalAlign:"middle",background:"#0d0d20"}}/>
                      {v.name}
                    </td>
                    <td><span className={`vehicle-type-badge ${BADGE[v.type]}`}>{v.type}</span></td>
                    <td>{v.year}</td>
                    <td>{v.km.toLocaleString("es-AR")}</td>
                    <td style={{fontWeight:700,color:"var(--accent)"}}>{fmt(v.price, v.currency)}</td>
                    <td><span style={{fontSize:"0.75rem",fontWeight:700,padding:"2px 8px",borderRadius:5,background:v.currency==="USD"?"rgba(34,180,100,0.13)":"rgba(232,0,28,0.1)",color:v.currency==="USD"?"#22b464":"var(--accent)",border:`1px solid ${v.currency==="USD"?"rgba(34,180,100,0.3)":"rgba(232,0,28,0.25)"}`}}>{v.currency||"ARS"}</span></td>
                    <td>{v.offer?<><span className="offer-dot"/>{v.offerTag||"Sí"}</>:<span style={{color:"var(--muted)"}}>—</span>}</td>
                    <td><div className="action-btns">
                      <button className="qr-btn" onClick={()=>setQrVehicle(v)}>📲 QR</button>
                      <button className="edit-btn" onClick={()=>setModal(v)}>✏️ Editar</button>
                      <button className="del-btn" onClick={()=>setConfirmDel(v)}>🗑 Eliminar</button>
                    </div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>
      {modal && <VehicleModal vehicle={modal==="add"?null:modal} onSave={handleSave} onClose={()=>setModal(null)}/>}
      {confirmDel && <ConfirmDelete vehicle={confirmDel} onConfirm={handleDeleteConfirmed} onCancel={()=>setConfirmDel(null)}/>}
      {qrVehicle && <QRModal vehicle={qrVehicle} onClose={()=>setQrVehicle(null)}/>}
      {toast && <Toast msg={toast.msg} type={toast.type}/>}
    </div>
  );
}

// ─── APP ──────────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("site");
  const [vehicles, setVehicles] = useState([]);
  const [deepVehicleId, setDeepVehicleId] = useState(null);

  useEffect(() => {
    const check = () => {
      const h = window.location.hash;
      if (h === "#/admin") { setPage(p => p==="admin"?"admin":"admin-login"); return; }
      const m = h.match(/^#\/v\/(\d+)$/);
      if (m) { setPage("site"); setDeepVehicleId(+m[1]); return; }
      setDeepVehicleId(null);
    };
    check(); window.addEventListener("hashchange", check);
    return () => window.removeEventListener("hashchange", check);
  }, []);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await fetch("http://localhost:4000/api/vehicles");
        if (!res.ok) throw new Error("HTTP " + res.status);
        const data = await res.json();
        setVehicles(Array.isArray(data) ? data : []);
      } catch (e) {
        console.error("No se pudo cargar desde la API", e);
        setVehicles([]);
      }
    };
    load();
  }, []);

  const goAdmin = () => { window.location.hash="#/admin"; setPage("admin-login"); };
  const goSite  = () => { window.location.hash=""; setPage("site"); };

  return (
    <>
      <style>{styles}</style>
      <div className="orb orb-1"/><div className="orb orb-2"/><div className="orb orb-3"/>
      {page==="site"        && <PublicSite vehicles={vehicles} onGoAdmin={goAdmin} deepVehicleId={deepVehicleId} onClearDeep={()=>setDeepVehicleId(null)}/>}
      {page==="admin-login" && <AdminLogin onLogin={()=>setPage("admin")} onBack={goSite}/>}
      {page==="admin"       && <AdminPanel vehicles={vehicles} setVehicles={setVehicles} onLogout={goSite}/>}
    </>
  );
}
